try {
  const raw = $input.first().json;
  const body = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
  const operation = String(body.operation || 'ai_search');
  const VALID_OPS = ['search','ai_search','publish','publish_bulk','get_property','get_stats'];
  if (!VALID_OPS.includes(operation)) {
    return [{ json: { __op: 'error', __error: true, success: false, error: 'Operacion desconocida: ' + operation, code: 400 } }];
  }
  const payload = (body.payload && typeof body.payload === 'object') ? body.payload : body;
  return [{ json: { __op: operation, operation, payload, source: 'web', requestedAt: new Date().toISOString() } }];
} catch(e) {
  return [{ json: { __op: 'error', __error: true, success: false, error: e.message, code: 500 } }];
}

try {
  const p = $input.first().json.payload;
  if (!p || !p.title || !p.comuna) throw new Error('VALIDATION: title y comuna son obligatorios.');
  const price = parseFloat(p.price);
  if (isNaN(price) || price <= 0) throw new Error('VALIDATION: price debe ser mayor a 0.');
  const userId = p.userId || null;
  return [{ json: { title:String(p.title).slice(0,255), description:String(p.description||'').slice(0,2000), price, region:String(p.region||''), comuna:String(p.comuna), address:String(p.address||''), bedrooms:Math.max(0,parseInt(p.bedrooms)||0), bathrooms:Math.max(0,parseInt(p.bathrooms)||0), sqm:parseFloat(p.sqm)||0, source_url:p.source_url?String(p.source_url):null, source:'web_dashboard', user_id: userId } }];
} catch(e) {
  return [{ json: { __error: true, success: false, error: e.message, code: 400 } }];
}

try {
  const raw = $input.first().json.payload;
  const userId = raw.userId || null;
  const items = Array.isArray(raw.properties) ? raw.properties : Array.isArray(raw) ? raw : [];
  if (items.length === 0) throw new Error('BULK_EMPTY: El lote esta vacio.');
  if (items.length > 1000) throw new Error('BULK_TOO_LARGE: Maximo 1000 propiedades.');
  const REQUIRED = ['title','comuna','price'];
  const valid = []; const skipped = [];
  for (const [i,p] of items.entries()) {
    const missing = REQUIRED.filter(k => !p[k]);
    if (missing.length) { skipped.push({row:i+1,reason:'Faltan: '+missing.join(', ')}); continue; }
    const price = parseFloat(p.price);
    if (isNaN(price)||price<=0) { skipped.push({row:i+1,reason:'price invalido'}); continue; }
    valid.push({ title:String(p.title).slice(0,255), description:String(p.description||'').slice(0,2000), price, region:String(p.region||''), comuna:String(p.comuna), address:String(p.address||''), bedrooms:Math.max(0,parseInt(p.bedrooms)||0), bathrooms:Math.max(0,parseInt(p.bathrooms)||0), sqm:parseFloat(p.sqm)||0, source_url:p.source_url?String(p.source_url):null, source:'bulk_import', user_id: userId });
  }
  if (valid.length === 0) throw new Error('BULK_ALL_INVALID: Ninguna fila paso la validacion. Filas omitidas: ' + JSON.stringify(skipped.slice(0,5)));
  return valid.map(p => ({ json: p }));
} catch(e) {
  return [{ json: { __error: true, success: false, error: e.message, code: 400 } }];
}

const results = $input.all();
const errItem = results.find(r => r.json.__error || r.json.error);
if (errItem) return [{ json: { success: false, error: errItem.json.error || 'Error en bulk insert', code: errItem.json.code || 500 } }];
return [{ json: { success: true, inserted: results.length, ids: results.map(r => r.json.id) } }];

let filters = {};
try {
  const raw = ($input.first().json.response || $input.first().json.payload?.prompt || '');
  const m = raw.match(/\{[^{}]*\}/s);
  if (m) filters = JSON.parse(m[0]);
} catch(e) {}
const userId = $input.first().json.payload?.userId || null;
return [{ json: { filters: { region: typeof filters.region==='string'?filters.region.trim():null, comuna:typeof filters.comuna==='string'?filters.comuna.trim():null, bedrooms:Number.isInteger(filters.bedrooms)?Math.max(0,filters.bedrooms):null, bathrooms:Number.isInteger(filters.bathrooms)?Math.max(0,filters.bathrooms):null, max_price:typeof filters.max_price==='number'?filters.max_price:null, property_type:['departamento','casa'].includes(filters.property_type)?filters.property_type:null, transaction_type:['venta','arriendo'].includes(filters.transaction_type)?filters.transaction_type:null, user_id: userId } } }];

const items = $input.all().map(i => i.json);
const errItem = items.find(i => i.__error || (i.error && typeof i.error === 'string' && i.error.length > 0));
if (errItem) {
  return [{ json: { success: false, error: errItem.error || 'Error desconocido', code: errItem.code || 500, timestamp: new Date().toISOString() } }];
}
const single = items.length === 1 ? items[0] : null;
return [{ json: { success: true, data: items.length===1 ? single : items, count: items.length, timestamp: new Date().toISOString() } }];
